var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"미래의 경쟁사를 이끌 사람한테 종신 계약을 하자니, 제정신이야?","JPN":"将来ライバル会社を営む予定の人間に終身契約を結ぼうだなんて、正気？","ENG":"You must be crazy, offering a lifetime contract to your future competitor.","TWN":"竟然想找未來的競爭對手簽終身契約？你腦袋沒問題吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"역시 손이 엄청 많이 가는 사장님이네. 이러는데 부하들이 아무도 안 말렸어?","JPN":"やっぱり手のかかる社長なんだな。こんなことをする前に、部下は誰も止めなかったの？","ENG":"You're such a handful, Boss. I can't believe no one tried to stop you until this point.","TWN":"果然是不好對付的老闆！不過你的員工都沒有阻止你嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"하긴, 그런 귀여운 로봇 뒤에 숨어 있었으니 다행이지.","JPN":"まあ、その可愛いロボットの裏に隠れていて正解だったかもな。","ENG":"You're lucky you're hiding behind that cute robot.","TWN":"幸好有這個可愛機器人當你的擋箭牌，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"안 그랬으면 이런 한심한 제안 같은 건 듣자마자 확 걷어차 버렸을 테니까.","JPN":"じゃなけりゃ、こんなバカげた提案なんか聞いた途端、蹴り飛ばしたと思うから。","ENG":"If you were here, I would have kicked you the moment you spoke of this pathetic offer.","TWN":"否則要是我是你的員工，聽到老闆這麼荒謬的提議，怎麼可能不飛踢你？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"으응? 아니면 처음부터 걷어차이고 싶었으려나? 사장님 혹시 그런 취향이었어?","JPN":"うん？　最初から蹴り飛ばされたかったとか？　社長ってもしかしてそんな趣味があんの？","ENG":"Mm, wait. Maybe that's what you want, being kicked at by a beautiful girl. Is it?","TWN":"還是？！你是抖Ｍ？一開始就是想被飛踢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭐, 난 원래 누구 밑에 있을 몸이 아니걸랑. 내 실력이면 업계 정상까지 금방이란 말씀.","JPN":"まあ、あたしは元々誰かの下で働ける性格じゃないし。あたしの実力だと、業界のトップクラスまであっという間ってこと！","ENG":"Well, I'm my own boss. I can get to the top of the industry in no time if I set my mind to it.","TWN":"不過，憑我的能力根本不需要依附在誰底下，登上業界的巔峰只是早晚的事。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"결국 사장님도 그런 나한테 꽂혀서 일찌감치 줄을 대려던 거 아니냐구♪","JPN":"結局社長もそんなあたしに惚れて、はやめにコネをつけておきたかっただけだろ♪","ENG":"You're offering me this position to nip the threat in the bud, aren't you? ♪","TWN":"老闆也是知道我有這樣的潛力，才想趁早網羅我吧？♪"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬하핫! 역시 그렇지? 그렇게까지 의지하고 싶다면 어쩔 수 없네!","JPN":"キャハハ！　やっぱりそうよね？　そこまで頼りたいっていうなら仕方ないな！","ENG":"Teehee! I knew it! Okay, if you're so scared, then I guess I have no choice.","TWN":"哇哈哈！我就知道！既然你這麼有看人的眼光，那我也只好勉為其難答應囉！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"좋아. 이 드라코 선장님이 못난 부하들을 어떻게 다스려야 하나 아주 친절하게 가르쳐 줄게.","JPN":"よし、このドラコ船長がマヌケな手下の扱い方について、一つ一つ丁寧に教えてやる。","ENG":"Alright, Captain Dracasia will teach you how to command your pathetic underlings.","TWN":"很好！德拉克船長該怎麼管理員工呢？我會非～常～親切地教育員工的～！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"아, 잠깐. 그러기 전에 계약서 인증샷 좀 찍고.","JPN":"ちょっと待って。その前に契約書の記念写真だけ撮らせろ。","ENG":"Oh, wait. Let me take a photo of my contract first, for my social media pages.","TWN":"欸！等等，口說無憑，在這契約書上蓋章吧！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};